import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import type { Activity } from '@motivation/shared';

/**
 * Create a manual activity and open the Activity Detail Hub for it (story 181).
 *
 * Replaces the old per-screen "create, then branch on `weight_training` →
 * strength screen, else stay" logic that the dashboard and day screen each had a
 * copy of. Now every new activity lands on the hub (story 179), where the user
 * attaches a cardio and/or workout component — or neither. One flow for runs,
 * lifts, both-at-once HIT sessions, and bare entries.
 */
export async function createActivityAndOpenHub(data: {
    title: string;
    type: string;
    date: string;
    duration_minutes?: number;
}): Promise<Activity> {
    const activity = await HealthService.createActivity(data);
    navigate(`/health/activity/${encodeURIComponent(activity.id)}`);
    return activity;
}
